#!/bin/bash

# Set environment variables from .env file (replace .env.example with your actual .env file)
eval $(docker-compose -f docker-compose.ci.yml config | grep AWS_ | xargs)

# Update deployment configuration based on environment (local or CI/CD)
if [ -z "$CI" ]; then
  export COMPOSE_FILE=docker-compose.yml
else
  export COMPOSE_FILE=docker-compose.ci.yml
fi

# Deploy using AWS CLI and Docker Compose
aws ecs update-service --cluster my-cluster --service my-service --force-new-deployment
docker-compose -f $COMPOSE_FILE up --no-deps --build